import React, { useEffect, useRef, useState } from "react";
import "./GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      emotion: "Welcome",
    },
  ]);

  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  // 🔽 Auto scroll to bottom
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // 🔐 SAVE CHAT WHEN USER LEAVES PAGE
  useEffect(() => {
    return () => {
      if (messages.length <= 1) return; // don't save empty chat

      const previousHistory =
        JSON.parse(localStorage.getItem("chatHistory")) || [];

      const newSession = {
        id: Date.now(),
        date: new Date().toLocaleString(),
        messages,
      };

      localStorage.setItem(
        "chatHistory",
        JSON.stringify([...previousHistory, newSession])
      );
    };
  }, [messages]);

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = {
      sender: "user",
      text: input,
    };

    const botMessage = {
      sender: "bot",
      emotion: "Listening",
      text: "I’m here with you 💜 Take your time. Would you like to tell me a bit more about what’s been on your mind?",
    };

    setMessages((prev) => [...prev, userMessage, botMessage]);
    setInput("");
  };

  return (
    <div className="general-chat-page">
      <h2 className="chat-title">🧠 General Chat</h2>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`chat-message ${msg.sender === "user" ? "user" : "bot"}`}
          >
            {msg.emotion && <span className="emotion-tag">💗 {msg.emotion}</span>}
            <p>{msg.text}</p>
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
